build for javascript backend
database is local memory

create a Counter table:
  value (number), default 0

when user calls GET /api/count:
  counters = get all Counter
  if counters is empty:
    saved = save {value: 0} to Counter
    send back {count: saved's value}
  else:
    first = first of counters
    send back {count: first's value}

when user calls POST /api/increment:
  counters = get all Counter
  if counters is empty:
    saved = save {value: 1} to Counter
    send back {count: saved's value}
  else:
    first = first of counters
    first's value = first's value + 1
    updated = save first to Counter
    send back {count: updated's value}

when user calls POST /api/reset:
  counters = get all Counter
  if counters is empty:
    saved = save {value: 0} to Counter
    send back {count: saved's value}
  else:
    first = first of counters
    first's value = 0
    updated = save first to Counter
    send back {count: updated's value}
